    int maxScore(string s) {
        int leftSum = 0, rightSum = 0;
        for (int i = 0; i < s.length(); i++) {
            if (s[i] == '0') {
                leftSum += 1;
            } else {
                rightSum += 1;
            }
        }
        return max(leftSum, rightSum);
    }
};
